import { ICommand } from "../Declaration9999";
import { SlotReel9999 } from "./SlotReel9999";
import { SlotSymbol9999 } from "./SlotSymbol9999";

interface ReelCascadeData {
    reelComp: SlotReel9999;
    deletions: any[];
    movements: any[];
}

/**
 * Command: Execute one cascade step across ALL reels.
 * Flow: Hide symbols → delay → Place new symbols + start drop
 * onComplete is called immediately after drop starts (NOT when drop finishes).
 */
export class CascadeStepCommand implements ICommand {
    duration = 0;

    private _reelDataList: ReelCascadeData[];
    private _ownerNode: cc.Node;
    private _stepData: any;
    private _onStepExecute: (step: any) => void;
    private _hideDuration = 0.25;
    private _scheduledCallback: () => void = null;
    private _dropHandler: () => void = null;

    constructor(
        reelDataList: ReelCascadeData[],
        ownerNode: cc.Node,
        stepData?: any,
        onStepExecute?: (step: any) => void,
    ) {
        this._reelDataList = reelDataList;
        this._ownerNode = ownerNode;
        this._stepData = stepData;
        this._onStepExecute = onStepExecute;
    }

    execute(onComplete?: () => void) {
        // Notify per-step callback (e.g. update winAmount)
        if (this._onStepExecute && this._stepData) {
            this._onStepExecute(this._stepData);
        }
        // --- Phase 1: Hide all deleted symbols across all reels ---
        this._reelDataList.forEach(data => {
            data.deletions.forEach(del => {
                const row = del.coordinates.row;
                const symbolNode = data.reelComp.listSymbols[row];
                if (symbolNode) {
                    symbolNode.getComponent(SlotSymbol9999).hide(this._hideDuration);
                }
            });
        });

        // --- Phase 2: After hide animation, place + start drop + wait for drops ---
        this._scheduledCallback = () => {
            this._scheduledCallback = null;
            let droppingCount = 0;

            this._reelDataList.forEach(data => {
                if (data.movements.length === 0) return;
                droppingCount++;
            });

            if (droppingCount === 0) {
                if (onComplete) onComplete();
                return;
            }

            // Register drop listener BEFORE starting drops
            let remaining = droppingCount;
            this._dropHandler = () => {
                remaining--;
                if (remaining <= 0) {
                    this._ownerNode.off("reelDropDone", this._dropHandler);
                    this._dropHandler = null;
                    if (onComplete) onComplete();
                }
            };
            this._ownerNode.on("reelDropDone", this._dropHandler);

            // NOW start drops
            this._reelDataList.forEach(data => {
                if (data.movements.length === 0) return;
                this._placeAndDrop(data);
            });
        };

        this._ownerNode.getComponent(cc.Component).scheduleOnce(
            this._scheduledCallback,
            this._hideDuration + 0.05
        );
    }

    cancel() {
        if (this._scheduledCallback) {
            const comp = this._ownerNode.getComponent(cc.Component);
            if (comp) comp.unschedule(this._scheduledCallback);
            this._scheduledCallback = null;
        }
    }

    private _placeAndDrop(data: ReelCascadeData) {
        const { reelComp, movements } = data;
        const listSymbols = reelComp.listSymbols;
        const symbolPositions = reelComp.symbolPositions;
        const symbolHeight = reelComp.symbolHeight;

        const sourceRows = new Set<number>();
        const existingMoves: any[] = [];
        const newMoves: any[] = [];

        movements.forEach(move => {
            if (move.from) {
                sourceRows.add(move.from.row);
                existingMoves.push(move);
            } else {
                newMoves.push(move);
            }
        });

        // Collect free (hidden) nodes that are NOT a source
        const freeNodes: cc.Node[] = [];
        for (let r = 0; r < listSymbols.length; r++) {
            const node = listSymbols[r];
            if (node && !node.active && !sourceRows.has(r)) {
                freeNodes.push(node);
            }
        }

        const newList: cc.Node[] = new Array(listSymbols.length).fill(null);
        const dropTargets: { node: cc.Node, targetY: number }[] = [];

        // Existing symbols → assign to new row
        existingMoves.forEach(move => {
            const symbolNode = listSymbols[move.from.row];
            if (symbolNode) {
                symbolNode.getComponent(SlotSymbol9999).idle();
                newList[move.to.row] = symbolNode;
                dropTargets.push({
                    node: symbolNode,
                    targetY: symbolPositions[move.to.row],
                });
            }
        });

        // New symbols → reuse free node, place above reel
        newMoves.sort((a, b) => a.to.row - b.to.row);
        newMoves.forEach((move, i) => {
            const symbolNode = freeNodes.length > 0 ? freeNodes.shift() : null;
            if (symbolNode) {
                symbolNode.getComponent(SlotSymbol9999).setCoreSymbol(move.symbol);
                symbolNode.getComponent(SlotSymbol9999).idle();
                newList[move.to.row] = symbolNode;

                // Place above top row
                symbolNode.y = symbolPositions[0] + symbolHeight * (newMoves.length - i);

                dropTargets.push({
                    node: symbolNode,
                    targetY: symbolPositions[move.to.row],
                });
            }
        });

        // Fill unchanged positions
        for (let r = 0; r < listSymbols.length; r++) {
            if (!newList[r]) {
                newList[r] = listSymbols[r];
            }
        }

        // Apply to reel → starts CASCADE_DROP in update()
        reelComp.applyDropTargets(newList, dropTargets);
    }
}

/**
 * Command: Wait for N reel "idle" events before completing.
 */
export class WaitForDropsCommand implements ICommand {
    duration = 0;

    private _ownerNode: cc.Node;
    private _getDropCount: () => number;
    private _handler: () => void = null;

    constructor(ownerNode: cc.Node, getDropCount: () => number) {
        this._ownerNode = ownerNode;
        this._getDropCount = getDropCount;
    }

    execute(onComplete?: () => void) {
        let remaining = this._getDropCount();
        if (remaining <= 0) {
            if (onComplete) onComplete();
            return;
        }

        this._handler = () => {
            remaining--;
            if (remaining <= 0) {
                this._ownerNode.off("reelDropDone", this._handler);
                this._handler = null;
                if (onComplete) onComplete();
            }
        };

        this._ownerNode.on("reelDropDone", this._handler);
    }

    cancel() {
        if (this._handler) {
            this._ownerNode.off("reelDropDone", this._handler);
            this._handler = null;
        }
    }
}

/**
 * Data for expanding wilds on a single reel.
 */
interface ExpandingWildReelData {
    reelComp: SlotReel9999;
    wildSpriteFrame: cc.SpriteFrame;  // tall wild sprite frame (wild_02)
}

/**
 * Command: Animate expanding wilds across reels.
 * Shows a full-reel wild overlay image on each affected reel.
 */
export class ExpandingWildsCommand implements ICommand {
    duration = 0.2;

    private _reelDataList: ExpandingWildReelData[];
    private _animDuration = 0.5;
    private _cancelled = false;

    constructor(reelDataList: ExpandingWildReelData[]) {
        this._reelDataList = reelDataList;
    }

    execute(onComplete?: () => void) {
        if (this._reelDataList.length === 0) {
            if (onComplete) onComplete();
            return;
        }

        let completedReels = 0;
        const totalReels = this._reelDataList.length;

        // Animate all affected reels simultaneously
        this._reelDataList.forEach(data => {
            if (this._cancelled) return;

            data.reelComp.showExpandingWild(
                data.wildSpriteFrame,
                this._animDuration,
                () => {
                    completedReels++;
                    if (completedReels >= totalReels && onComplete && !this._cancelled) {
                        onComplete();
                    }
                }
            );
        });
    }

    cancel() {
        this._cancelled = true;
        // Force show the overlay immediately without animation
        this._reelDataList.forEach(data => {
            if (data.reelComp.hasExpandingWild) {
                // Already showing, just stop animation
                const node = (data.reelComp as any)._expandingWildNode;
                if (node) {
                    cc.Tween.stopAllByTarget(node);
                    node.opacity = 255;
                    node.scaleY = 1;
                }
            }
        });
    }
}
