/**
 * CommandManager.ts
 * The Invoker in the Command Pattern.
 * Supports both immediate execution and sequential queue.
 * After each command's execute() completes, waits for command.duration seconds
 * before running the next command. Duration can be cancelled to skip the wait.
 */

import { ICommand } from './ICommand';

const { ccclass, property } = cc._decorator;

@ccclass
export class CommandManagerComp extends cc.Component {

    private _executedCommands: ICommand[] = [];
    private _queue: ICommand[] = [];
    private _isRunning = false;
    private _onQueueComplete: () => void = null;
    private _currentCommand: ICommand = null;
    private _waitingForDuration = false;
    private _durationCallback: () => void = null;

    /**
     * Executes a command immediately (fire-and-forget).
     */
    public executeCommand(command: ICommand) {
        command.execute();
        this._executedCommands.push(command);
    }

    /**
     * Add commands to the sequential queue.
     * Commands will execute one after another, each waiting for onComplete.
     */
    public enqueue(command: ICommand) {
        this._queue.push(command);
    }

    /**
     * Add multiple commands at once.
     */
    public enqueueAll(commands: ICommand[]) {
        commands.forEach(cmd => this._queue.push(cmd));
    }

    /**
     * Start running the queue sequentially.
     * @param onComplete - called when all queued commands are done
     */
    public runQueue(onComplete?: () => void) {
        this._onQueueComplete = onComplete || null;
        this._runNext();
    }

    /**
     * Cancel the current command's duration wait and immediately proceed to next.
     */
    public cancelCurrentDuration() {
        if (!this._waitingForDuration || !this._currentCommand) return;

        // Cancel the command's internal state
        this._currentCommand.cancel();

        // Unschedule the duration wait
        if (this._durationCallback) {
            this.unschedule(this._durationCallback);
            this._durationCallback = null;
        }

        this._waitingForDuration = false;

        // Immediately proceed to next command
        this._runNext();
    }

    /**
     * Clear all queued commands.
     */
    public clearQueue() {
        // Cancel current duration if waiting
        if (this._waitingForDuration && this._currentCommand) {
            this._currentCommand.cancel();
            if (this._durationCallback) {
                this.unschedule(this._durationCallback);
                this._durationCallback = null;
            }
        }
        this._queue = [];
        this._isRunning = false;
        this._waitingForDuration = false;
        this._currentCommand = null;
    }

    public isRunning(): boolean {
        return this._isRunning;
    }

    private _runNext() {
        if (this._queue.length === 0) {
            this._isRunning = false;
            this._currentCommand = null;
            if (this._onQueueComplete) {
                this._onQueueComplete();
                this._onQueueComplete = null;
            }
            return;
        }

        this._isRunning = true;
        const command = this._queue.shift();
        this._currentCommand = command;
        this._executedCommands.push(command);

        command.execute(() => {
            // When command's execute completes, wait for duration before next
            this._startDurationWait(command);
        });
    }

    private _startDurationWait(command: ICommand) {
        if (command.duration > 0) {
            this._waitingForDuration = true;
            this._durationCallback = () => {
                this._waitingForDuration = false;
                this._durationCallback = null;
                this._runNext();
            };
            this.scheduleOnce(this._durationCallback, command.duration);
        } else {
            // No duration, proceed immediately
            this._runNext();
        }
    }

    /**
     * Optional: Undo the last executed command.
     */
    public undoLastCommand() {
        if (this._executedCommands.length > 0) {
            const command = this._executedCommands.pop();
            if (command.undo) {
                command.undo();
            }
        }
    }
}
