import { ObserverComp } from "./ObserverComp";

const { ccclass, property } = cc._decorator;

@ccclass
export class SubjectComp extends cc.Component {
    private _observer: ObserverComp = null;
    protected onLoad(): void {
        this.initObserver();
    }

    private initObserver() {
        if (this._observer) return;
        const ObserverNode = cc.find('ObserverNode');
        if (ObserverNode) {
            this._observer = ObserverNode.getComponent(ObserverComp);
        } else {
            console.warn("SubjectComp: 'Canvas' node not found in scene.");
        }
    }

    public getConfig(): any {
        this.initObserver();
        return this._observer.getConfig();
    }

    public getAssetsManager(): any {
        this.initObserver();
        return this._observer.getAssetManager();
    }

    public showWaiting() {
        this.initObserver();
        this._observer.getPreloaderManager().show();
    }

    public showPreload() {
        this.initObserver();
        this._observer.getPreloaderManager().show();
    }

    public hideLoading() {
        this.initObserver();
        this._observer.getPreloaderManager().hide();
    }

    showPopup(popupName: string, data: any) {
        this.initObserver();
        this._observer.getPopupManager().showPopup(popupName, data);
    }


    public fireEvent(event: string, ...args: any[]) {
        this.initObserver();
        this._observer.getEventManager().emit(event, ...args);
    }

    public registerEvent(event: string, callback: Function, target?: any) {
        this.initObserver();
        this._observer.getEventManager().on(event, callback, target);
    }
}
