
import { PopupConfig } from '../Constants/PopupConfig';
import { GameDataEvents } from '../DataModel/GameDataEvents';
import { SubjectComp } from '../Patterns/Observer/SubjectComp';
import { GameAPI } from '../Managers/api';

const { ccclass, property } = cc._decorator;
@ccclass
export class GameController extends SubjectComp {
    @property(cc.Node) btnSpin: cc.Node = null;
    @property(cc.Node) btnAutoSpin: cc.Node = null;
    @property(cc.Node) btnNewBet: cc.Node = null;
    @property(SubjectComp) reelControl: SubjectComp = null;
    @property(cc.Label) lblWinAmount: cc.Label = null;
    @property(cc.Label) lblBalanceAmount: cc.Label = null;
    @property(cc.Label) lblBetAmount: cc.Label = null;
    private _apiListener: IApiListener;
    private _autoSpinValue: number = -1;
    private _betAmount: number = 0;

    protected onLoad() {
        super.onLoad();
        this.setupUI();
        this.listenNodeEvents();
        this.listenScriptsEvent();
    }

    protected setupUI() {
        this.updateBetAmount(this.getConfig().getConfigByKey("BET_AMOUNTS")[0]);
        this.updateWinAmount(0);
        this.updateBalanceAmount(0);
        this.updateSpinButtonState(false);
        this.updateAutoSpinButtonState(false);
    }

    protected listenNodeEvents() {
        this.btnSpin.on("click", this.onClickSpin, this);
        this.btnAutoSpin.on("click", this.onClickAutoSpin, this);
        this.btnNewBet.on("click", this.onClickNewBet, this);
        this.reelControl.node.on(GameDataEvents.SCRIPT_EVENTS.CASCADE_ALL_DONE, this._onCascadeAllDone, this);
        this.reelControl.node.on(GameDataEvents.SCRIPT_EVENTS.SPIN_ALL_DONE, this._onSpinAllDone, this);
    }

    protected listenScriptsEvent() {
        this.node.on(GameDataEvents.SCRIPT_EVENTS.SETUP_GAME, this.onSetupGame, this);
        this.node.on(GameDataEvents.SCRIPT_EVENTS.SPIN_RESULT, this.onSpinResult, this);
        this.node.on(GameDataEvents.SCRIPT_EVENTS.SPIN_COMPLETE, this.onSpinComplete, this);
        this.node.on(GameDataEvents.SCRIPT_EVENTS.PIN_RESTORE_NOTIFY, this.onSpinRestoreNotify, this);
        this.node.on(GameDataEvents.SCRIPT_EVENTS.LAST_SESSION, this.onLastSession, this);
    }

    public setApiListener(listener: IApiListener) {
        if (listener) {
            this._apiListener = listener;
        }
        cc.log("setApiListener", listener);
    }

    private _currentRoundId = "";
    private _pendingSteps: any[] = null;
    private _pendingExpandingWilds: any[] = null;

    private onClickSpin() {
        this.updateSpinButtonState(false);
        this.updateAutoSpinButtonState(this._autoSpinValue > 0);
        this.spin();
    }

    private onClickNewBet() {
        this.showPopup(PopupConfig.popupName().SELECT, {
            data: {
                title: "New Bet",
                message: "Select bet amount",
                textConfirm: "Yes",
                textCancel: "No",
                cbConfirm: (value) => {
                    this.updateBetAmount(value);
                },
                cbCancel: () => { },
                selectData: this.getConfig().getConfigByKey("BET_AMOUNTS")
            }
        });
    }

    protected onClickAutoSpin() {
        if (this._autoSpinValue <= 0) {
            this.showPopup(PopupConfig.popupName().SELECT, {
                data: {
                    title: "Auto Spin",
                    message: "Select number of spins",
                    textConfirm: "Yes",
                    textCancel: "No",
                    cbConfirm: (value) => {
                        this._autoSpinValue = value;
                        this.sendAutoSpin();
                    },
                    cbCancel: () => { },
                    selectData: this.getConfig().getConfigByKey("AUTO_SPIN_VALUES")
                }
            });
        }
        else {
            this.stopAutoSpin();
        }
    }

    protected spin() {
        this._apiListener && this._apiListener.callApiGetSpinResult(this._betAmount);
        (this.reelControl as any).startSpin();
    }

    private sendAutoSpin() {
        cc.log("start auto spin", this._autoSpinValue);
        this.updateSpinButtonState(false);
        this.spin();
        this.updateAutoSpinValue();
    }

    private updateAutoSpinValue() {
        --this._autoSpinValue;
        if (this._autoSpinValue <= 0) {
            this.stopAutoSpin();
        } else {
            this.btnAutoSpin.getComponentInChildren(cc.Label).string = `${this._autoSpinValue}\nStop`;
        }
    }

    private stopAutoSpin() {
        cc.log("stop auto spin");
        this.btnAutoSpin.getComponentInChildren(cc.Label).string = "Auto";
        this._autoSpinValue = -1;
    }

    protected onLastSession(data) {
        cc.warn("onLastSession", data);
        if (!data || (Array.isArray(data.rounds) && data.rounds.length === 0)) {
            this.updateSpinButtonState(true);
            this.updateAutoSpinButtonState(true);
            return;
        }

    }

    protected onSetupGame(data) {
        cc.warn("onSetupGame", data);
        this.updateBalanceAmount(GameAPI.instance.toDisplayAmount(data.balance));
        this._apiListener && this._apiListener.callApiGetSession();
    }

    protected onSpinResult(data) {
        cc.warn("onSpinResult", data);

        const steps = data.wager.data;
        this._currentRoundId = data.roundId || "";
        const step0 = steps[0];

        // Reset win amount for new spin
        this.updateWinAmount(0);

        // Emit counter updates
        this._emitCounterUpdate(step0.counters);

        // Check if Power Mode is active
        const isPowerMode = step0.state === "BASE_POWER_MODE";
        const expandingWilds = step0.transforms && step0.transforms.EXPANDING_WILDS_MODIFIER;
        const hasExpandingWilds = expandingWilds && expandingWilds.length > 0;

        // Store pending data — will be processed after spin animation completes
        this._pendingSteps = steps;
        this._pendingExpandingWilds = (isPowerMode && hasExpandingWilds) ? expandingWilds : null;

        if (isPowerMode && hasExpandingWilds) {
            // Power Mode: show original_panel (before wild expansion)
            (this.reelControl as any).onReceiveResult(step0.original_panel.reels);
        } else {
            // Normal flow: show final panel directly
            (this.reelControl as any).onReceiveResult(step0.panel.reels);
        }
        // → wait for spinAllDone event
    }

    /** Called when all reels finish their spin return animation */
    private _onSpinAllDone() {
        const steps = this._pendingSteps;
        const expandingWilds = this._pendingExpandingWilds;
        this._pendingSteps = null;
        this._pendingExpandingWilds = null;

        if (!steps) return;

        // Update win for step 0
        this.updateWinAmount(GameAPI.instance.toDisplayAmount(steps[0].round_winnings));

        if (expandingWilds) {
            // Animate expanding wilds, then process cascades
            (this.reelControl as any).applyExpandingWilds(expandingWilds, () => {
                this._processCascades(steps);
            });
        } else {
            this._processCascades(steps);
        }
    }

    private _processCascades(steps: any[]) {
        if (steps.length > 1) {
            const cascadeSteps = steps.slice(1);
            this.scheduleOnce(() => {
                (this.reelControl as any).setCascadeQueue(cascadeSteps, (step: any) => {
                    // Called per cascade step when it executes
                    this.updateWinAmount(GameAPI.instance.toDisplayAmount(step.round_winnings));
                });
            }, 0.5);
        } else {
            this._completeRound();
        }
    }

    private _emitCounterUpdate(counters: any) {
        if (!counters) return;
        this.node.emit(GameDataEvents.SCRIPT_EVENTS.COUNTER_UPDATE, counters);
    }

    private _onCascadeAllDone() {
        cc.log("All cascades done");
        this._completeRound();
    }

    private _completeRound() {
        if (this._currentRoundId) {
            this._apiListener && this._apiListener.calApiGetSpinComplete(this._currentRoundId);
        }
    }

    protected onSpinComplete(data) {
        cc.warn("onSpinComplete", data);
        if (data && data.balance != null) {
            this.updateBalanceAmount(GameAPI.instance.toDisplayAmount(data.balance));
        }
        if (this._autoSpinValue > 0) {
            this.sendAutoSpin();
        }
        this.updateSpinButtonState(true);
        this.updateAutoSpinButtonState(true);
    }

    // ─── HUD Label Helpers ───

    protected updateWinAmount(value: number) {
        if (this.lblWinAmount) {
            this.lblWinAmount.string = value.toFixed(2);
        }
    }

    protected updateBalanceAmount(value: number) {
        if (this.lblBalanceAmount) {
            this.lblBalanceAmount.string = value.toFixed(2);
        }
    }

    protected updateBetAmount(value: number) {
        this._betAmount = value;
        this.lblBetAmount.string = value.toFixed(2);
    }

    protected onSpinRestoreNotify(data) {
        cc.warn("onSpinRestoreNotify", data);
        // Disable spin button while popup is shown
        this.updateSpinButtonState(false);
        this.updateAutoSpinButtonState(false);

        // Show popup asking user if they want to restore the last session
        this.showPopup(PopupConfig.popupName().NOTIFY, {
            data: {
                title: "Session Recovery",
                message: data.message,
                textConfirm: "Yes",
                textCancel: "No",
                cbConfirm: () => {
                    // User wants to restore → call restore API (spin stays disabled until restore completes)
                    (this.reelControl as any).startSpin();
                    this._apiListener && this._apiListener.callApiSpinRestore();
                },
                cbCancel: () => {
                    // User declined → re-enable spin button for normal play
                    this.updateSpinButtonState(true);
                    this.updateAutoSpinButtonState(true);
                }
            },
        });
    }

    private updateSpinButtonState(interactable: boolean) {
        if (this._autoSpinValue > 0) {
            interactable = false;
        }
        this.btnSpin.getComponent(cc.Button).interactable = interactable;
    }

    private updateAutoSpinButtonState(interactable: boolean) {
        this.btnAutoSpin.getComponent(cc.Button).interactable = interactable;
    }

}

export interface IApiListener {
    callApiGetSession(): Promise<void>;
    callApiGetSpinResult(betAmount: number): Promise<void>;
    callApiSpinRestore(): Promise<void>;
    calApiGetSpinComplete(roundId: string): Promise<void>;
}