import { GameDataEvents } from "./GameDataEvents";
import { GameDataParser } from "./GameDataParser";
export class GameDataWriter {
    _parser: GameDataParser;
    _lastSpinResult = null;
    constructor() {
        this._parser = new GameDataParser();
    }

    public makeScriptSetupGame(res) {
        let scripts = [];
        scripts.push({
            code: GameDataEvents.SCRIPT_EVENTS.SETUP_GAME,
            data: res
        })
        return scripts;
    }

    public makeScriptLastSession(res) {
        let scripts = [];
        scripts.push({
            code: GameDataEvents.SCRIPT_EVENTS.LAST_SESSION,
            data: res
        })
        if (res.rounds && res.rounds.length > 0) {
            const spinResult = {
                roundId: res.rounds[0].roundId,
                wager: res.rounds[0].wagers[0]
            }
            this._lastSpinResult = spinResult;
            scripts.push({
                code: GameDataEvents.SCRIPT_EVENTS.PIN_RESTORE_NOTIFY,
                data: {
                    message: "You got another spin uncomplete"
                }
            })
        }
        return scripts;
    }

    public makeScriptSpinResult(res) {
        let scripts = [];
        scripts.push({
            code: GameDataEvents.SCRIPT_EVENTS.SPIN_RESULT,
            data: res
        })
        this._lastSpinResult = res;
        return scripts;
    }

    public makeScriptRestoreSpinResult() {
        let scripts = [];
        scripts = scripts.concat(this.makeScriptSpinResult(this._lastSpinResult));
        return scripts;
    }

    public makeScriptSpinComplete(res) {
        let scripts = [];
        scripts.push({
            code: GameDataEvents.SCRIPT_EVENTS.SPIN_COMPLETE,
            data: res
        })
        return scripts;
    }
}

