import { SubjectComp } from "../Declaration9999";
import { SlotConstants9999 } from "./SlotConstants9999";
import { SlotSymbol9999 } from "./SlotSymbol9999";

const { ccclass, property } = cc._decorator;

enum ReelState {
    IDLE = "idle",
    SPINNING = "spinning",
    RETURNING = "returning",
    CASCADE_DROP = "cascadeDrop",
}

export interface DropTarget {
    node: cc.Node;
    targetY: number;
}

@ccclass
export class SlotReel9999 extends SubjectComp {
    @property({ displayName: "symbol", type: cc.Prefab }) symbol: cc.Prefab = null;

    private _listSymbols: cc.Node[] = [];
    private _symbolPositions: number[] = [];
    private _state: ReelState = ReelState.IDLE;
    private _delay = 0;
    private _delaySpinResult = 0;
    private _spinTo = 0;
    private _originY = 0;
    private _symbolHeight = 0;
    private _rows = 0;
    private _resultData = [];
    private _dropTargets: DropTarget[] = [];

    // ======================= GETTERS =======================

    get listSymbols() { return this._listSymbols; }
    get symbolPositions() { return this._symbolPositions; }
    get symbolHeight() { return this._symbolHeight; }

    // ======================= SETUP =======================

    onLoad() {
        super.onLoad();
    }

    public setReel(col: number, rows: number) {
        this.node.removeAllChildren(true);
        this._listSymbols = [];
        this._symbolPositions = [];
        this._rows = rows;
        const { height: symbolHeight, anchorY: symbolAnchorY } = this.symbol.data;
        this._symbolHeight = symbolHeight;
        this._spinTo = rows * symbolHeight + symbolHeight * symbolAnchorY;
        for (let r = 0; r < rows; r++) {
            let symbolNode = cc.instantiate(this.symbol);
            symbolNode.getComponent(SlotSymbol9999).setCoreSymbol(SlotConstants9999.DefaultSymbol[col][r]);
            symbolNode.name += "_" + col + "_" + r;
            symbolNode.y -= r * this._symbolHeight;
            this.node.addChild(symbolNode);
            this._listSymbols.push(symbolNode);
        }
        this._originY = this.node.y;

        // Save original Y positions
        this.scheduleOnce(() => {
            this._symbolPositions = [];
            for (let r = 0; r < this._listSymbols.length; r++) {
                this._symbolPositions[r] = this._listSymbols[r].y;
            }
        }, 0);
    }

    // ======================= EXPANDING WILD =======================

    private _originalSymbolHeight = 0;
    private _isExpandingWild = false;

    /**
     * Show expanding wild: change the first symbol (row 0) to the tall wild image,
     * resize it to cover the full reel, and hide all other symbols below.
     */
    public showExpandingWild(wildSpriteFrame: cc.SpriteFrame, duration: number = 0.5, onComplete?: () => void) {
        this._isExpandingWild = true;

        const firstSymbol = this._listSymbols[0];
        if (!firstSymbol) return;

        const symbolComp = firstSymbol.getComponent(SlotSymbol9999);

        // Save original height for restore
        if (this._originalSymbolHeight === 0) {
            this._originalSymbolHeight = firstSymbol.height;
        }

        // Hide all symbols below the first one
        for (let i = 1; i < this._listSymbols.length; i++) {
            this._listSymbols[i].active = false;
        }

        // Set the first symbol to the tall wild sprite
        symbolComp.deactive();
        symbolComp.core.active = true;
        symbolComp.core.getComponent(cc.Sprite).spriteFrame = wildSpriteFrame;

        // Resize to cover full reel height
        const reelHeight = this._rows * this._symbolHeight;
        firstSymbol.anchorY = 1;
        firstSymbol.y = this._symbolPositions[0] + this._symbolHeight * 0.5;
        firstSymbol.height = reelHeight;

        // Animate: scale in
        firstSymbol.scaleY = 0;
        firstSymbol.opacity = 0;

        cc.Tween.stopAllByTarget(firstSymbol);
        cc.tween(firstSymbol)
            .to(duration * 0.6, { scaleY: 1.05, opacity: 255 }, { easing: 'backOut' })
            .to(duration * 0.4, { scaleY: 1.0 }, { easing: 'bounceOut' })
            .call(() => {
                if (onComplete) onComplete();
            })
            .start();
    }

    /**
     * Restore all symbols to normal state after expanding wild.
     */
    public hideExpandingWild() {
        if (!this._isExpandingWild) return;
        this._isExpandingWild = false;

        // Restore first symbol
        const firstSymbol = this._listSymbols[0];
        if (firstSymbol) {
            cc.Tween.stopAllByTarget(firstSymbol);
            firstSymbol.anchorY = 0.5;
            if (this._originalSymbolHeight > 0) {
                firstSymbol.height = this._originalSymbolHeight;
            }
            firstSymbol.y = this._symbolPositions[0];
            firstSymbol.scaleY = 1;
            firstSymbol.opacity = 255;
        }

        // Show all symbols again
        for (const sym of this._listSymbols) {
            sym.active = true;
            sym.getComponent(SlotSymbol9999).idle();
        }
    }

    /** Check if expanding wild is currently shown */
    public get hasExpandingWild(): boolean {
        return this._isExpandingWild;
    }

    // ======================= SPIN =======================

    public spin(delay) {
        // Clean up expanding wild overlay from previous spin
        this.hideExpandingWild();
        this._state = ReelState.SPINNING;
        this._delay = delay;
        this._delaySpinResult = delay;
        this._resultData = [];
    }

    public onReceiveResult(resultData) {
        this._resultData = resultData;
        if (this._state === ReelState.IDLE) {
            this._spinResult();
        }
    }

    private _spinResult() {
        for (let i = 0; i < this._listSymbols.length; i++) {
            this._listSymbols[i].getComponent(SlotSymbol9999).setCoreSymbol(this._resultData[i]);
            this._listSymbols[i].getComponent(SlotSymbol9999).idle();
        }
        this.node.y = this._spinTo;
        this._resultData = [];
        this._state = ReelState.RETURNING;
    }

    // ======================= CASCADE =======================

    /**
     * Called by CascadePlaceCommand to update symbol list and start dropping.
     */
    public applyDropTargets(newList: cc.Node[], dropTargets: DropTarget[]) {
        this._listSymbols = newList;
        this._dropTargets = dropTargets;
        this._state = ReelState.CASCADE_DROP;
    }

    // ======================= UPDATE =======================

    protected update(dt: number): void {
        switch (this._state) {
            case ReelState.CASCADE_DROP:
                this._updateCascadeDrop(dt);
                break;
            case ReelState.RETURNING:
                this._updateReturning(dt);
                break;
            case ReelState.SPINNING:
                this._updateSpinning(dt);
                break;
        }
    }

    private _updateCascadeDrop(dt: number) {
        const dropSpeed = 1200;
        const moveAmount = dropSpeed * dt;
        let allDone = true;

        for (let i = 0; i < this._dropTargets.length; i++) {
            const { node, targetY } = this._dropTargets[i];
            if (node.y > targetY) {
                node.y -= moveAmount;
                if (node.y <= targetY) {
                    node.y = targetY;
                } else {
                    allDone = false;
                }
            }
        }

        if (allDone) {
            this._dropTargets = [];
            this._state = ReelState.IDLE;
            this.node.emit(ReelState.IDLE);
        }
    }

    private _updateReturning(dt: number) {
        if (this._delaySpinResult > 0) {
            this._delaySpinResult -= dt;
            if (this._delaySpinResult > 0) return;
        }

        const returnSpeed = 1500;
        const moveAmount = returnSpeed * dt;
        this.node.y -= moveAmount;

        if (this.node.y <= this._originY) {
            this.node.y = this._originY;
            this._state = ReelState.IDLE;
            this.node.emit(ReelState.IDLE);
        }
    }

    private _updateSpinning(dt: number) {
        if (this._delay > 0) {
            this._delay -= dt;
            if (this._delay > 0) return;
        }

        const spinSpeed = 1500;
        const moveAmount = spinSpeed * dt;
        this.node.y -= moveAmount;

        if (this.node.y <= -this._spinTo) {
            this.node.y = -this._spinTo;
            this._state = ReelState.IDLE;

            if (this._resultData.length > 0) {
                this._spinResult();
            }
        }
    }
}