import { CommandManagerComp, GameDataEvents, SubjectComp } from "../Declaration9999";
import { CascadeStepCommand, ExpandingWildsCommand } from "./CascadeCommands9999";
import { SlotReel9999 } from "./SlotReel9999";

const { ccclass, property } = cc._decorator;

@ccclass
export class ReelControl9999 extends SubjectComp {
    @property({ displayName: "reel", type: cc.Prefab }) reel = null;
    @property({ displayName: "col" }) cols = 6;
    @property({ displayName: "row" }) rows = 5;

    private listReel: cc.Node[] = [];
    private commandManager: CommandManagerComp = null;
    private _currentDropCount = 0;
    private _spinningReelsCount = 0;
    private _isSpinning = false;

    onLoad() {
        super.onLoad();
        this.commandManager = this.node.addComponent(CommandManagerComp);
        this.setupReels();
    }

    private setupReels() {
        this.node.removeAllChildren(true);
        for (let i = 0; i < this.cols; i++) {
            let reelNode = cc.instantiate(this.reel);
            this.node.addChild(reelNode);
            let reelComp = reelNode.getComponent(SlotReel9999);
            reelComp.setReel(i, this.rows);
            this.listReel.push(reelNode);

            // When reel finishes its animation (spin return or cascade drop)
            reelNode.on("idle", () => {
                this.node.emit("reelDropDone");
                if (this._isSpinning) {
                    this._onReelSpinDone();
                }
            });
        }
    }

    // ======================= SPIN =======================

    public startSpin() {
        this._isSpinning = true;
        this._spinningReelsCount = this.listReel.length;
        let delay = 0;
        for (let col = 0; col < this.listReel.length; col++) {
            const reelComp = this.listReel[col].getComponent(SlotReel9999);
            reelComp.spin(delay);
            delay += 0.05;
        }
    }

    /** Called when a reel finishes its spin return animation */
    private _onReelSpinDone() {
        this._spinningReelsCount--;
        if (this._spinningReelsCount <= 0) {
            this._spinningReelsCount = 0;
            this._isSpinning = false;
            this.node.emit(GameDataEvents.SCRIPT_EVENTS.SPIN_ALL_DONE);
        }
    }

    public onReceiveResult(resultDatas) {
        for (let col = 0; col < resultDatas.length; col++) {
            const colData = resultDatas[col];
            const reelComp = this.listReel[col].getComponent(SlotReel9999);
            reelComp.onReceiveResult(colData);
        }
    }

    // ======================= EXPANDING WILDS =======================

    /**
     * Process expanding wilds transform and animate.
     * Shows original_panel first, then animates wilds expanding.
     * @param originalReels - the original_panel.reels (before transform)
     * @param expandingWildsTransforms - EXPANDING_WILDS_MODIFIER data array
     * @param onComplete - called when all expanding wild animations are done
     */
    public applyExpandingWilds(expandingWildsTransforms: any[], onComplete?: () => void) {
        if (!expandingWildsTransforms || expandingWildsTransforms.length === 0) {
            if (onComplete) onComplete();
            return;
        }

        // Get the tall wild sprite frame from AssetsManager
        const wildSpriteFrame = this.getAssetsManager().getCoreSymbolByCode("WI_EX");
        if (!wildSpriteFrame) {
            cc.warn("ExpandingWilds: WI_EX sprite frame not found");
            if (onComplete) onComplete();
            return;
        }

        // Collect unique affected reels from all transforms
        const affectedReels = new Set<number>();
        for (const transform of expandingWildsTransforms) {
            const sourceSymbol = transform.source && transform.source[0];
            if (sourceSymbol) {
                affectedReels.add(sourceSymbol.coordinates.reel);
            }
        }

        // Build reel data list
        const reelDataList = [];
        affectedReels.forEach(reelIndex => {
            if (reelIndex < this.listReel.length) {
                reelDataList.push({
                    reelComp: this.listReel[reelIndex].getComponent(SlotReel9999),
                    wildSpriteFrame: wildSpriteFrame,
                });
            }
        });

        if (reelDataList.length === 0) {
            if (onComplete) onComplete();
            return;
        }

        // Use command manager to execute expanding wilds
        this.commandManager.clearQueue();
        this.commandManager.enqueue(new ExpandingWildsCommand(reelDataList));
        this.commandManager.runQueue(() => {
            if (onComplete) onComplete();
        });
    }

    // ======================= CASCADE =======================

    /**
     * Queue cascade steps and execute them sequentially using CommandManager.
     * Per step: CascadeStepCommand (hide+place all reels) → WaitForDrops → Delay
     */
    public setCascadeQueue(cascadeSteps: any[], onStepExecute?: (step: any) => void) {
        this.commandManager.clearQueue();

        for (const step of cascadeSteps) {
            const cascades = step.transforms && step.transforms.AVALANCHE_CASCADES;
            if (!cascades || cascades.length === 0) continue;

            const cascadeData = cascades[0];
            const { deletions, movements } = cascadeData;
            if ((!deletions || deletions.length === 0) && (!movements || movements.length === 0)) continue;

            // Group per reel
            const delPerReel = this._groupByReel(deletions || [], d => d.coordinates.reel);
            const movePerReel = this._groupByReel(movements || [], m => m.to.reel);

            // Build reel data list
            const reelDataList = [];
            for (let col = 0; col < this.listReel.length; col++) {
                const dels = delPerReel.get(col) || [];
                const moves = movePerReel.get(col) || [];
                if (dels.length === 0 && moves.length === 0) continue;

                reelDataList.push({
                    reelComp: this.listReel[col].getComponent(SlotReel9999),
                    deletions: dels,
                    movements: moves,
                });
            }

            if (reelDataList.length === 0) continue;

            // CascadeStep: hide → place → drop → wait for drops to finish
            this.commandManager.enqueue(
                new CascadeStepCommand(reelDataList, this.node, step, onStepExecute)
            );
        }

        // Run the queue
        this.commandManager.runQueue(() => {
            cc.log("cascadeAllDone");
            this.node.emit(GameDataEvents.SCRIPT_EVENTS.CASCADE_ALL_DONE);
        });
    }

    private _groupByReel(items: any[], getReelFn: (item: any) => number): Map<number, any[]> {
        const map = new Map<number, any[]>();
        items.forEach(item => {
            const reel = getReelFn(item);
            if (!map.has(reel)) map.set(reel, []);
            map.get(reel).push(item);
        });
        return map;
    }
}