/**
 * NetworkManager.ts
 * A TRUE Singleton because it handles persistent network state
 */

import { GameAPI } from "./api";

const { ccclass, property } = cc._decorator;

@ccclass
export class NetworkManagerComp extends cc.Component {

    private static _instance: NetworkManagerComp = null;

    /**
     * Singleton accessor for the NetworkManagerComp.
     */
    public static get instance(): NetworkManagerComp {
        if (!this._instance) {
            // Cocos Creator 2.x doesn't allow 'new Component' easily from static
            // Usually we'd find the node or create one.
            // But since this is a singleton that might persist...
            console.warn("NetworkManagerComp instance is missing. Create a Node with NetworkManagerComp attached.");
        }
        return this._instance;
    }

    async onLoad() {
        NetworkManagerComp._instance = this;
    }

    async authenticate() {
        return await GameAPI.instance.authenticate();
    }

    async callApiGetSession() {
        return await GameAPI.instance.recover();
    }

    async callApiGetSpinResult(betAmount: number) {
        return await GameAPI.instance.play(betAmount);
    }

    async callApiGetSpinComplete(roundId: string) {
        return await GameAPI.instance.complete(roundId);
    }
}
