import { SubjectComp } from "../Declaration9999";

const { ccclass, property } = cc._decorator;

@ccclass
export class SlotSymbol9999 extends SubjectComp {
    @property(cc.Node) core: cc.Node = null;
    @property(cc.Node) blur: cc.Node = null;
    @property(cc.Node) spine: cc.Node = null;

    setCoreSymbol(code: string) {
        this.deactive();
        this.core.active = true;
        this.core.getComponent(cc.Sprite).spriteFrame = this.getAssetsManager().getCoreSymbolByCode(code);
    }

    deactive() {
        this.core.active = false;
        this.blur.active = false;
        this.spine.active = false;
    }

    /** Hide symbol with zoom + fade out animation */
    hide(dur: number) {
        cc.Tween.stopAllByTarget(this.node);
        cc.tween(this.node)
            .to(dur, { scale: 0, opacity: 0 }, { easing: 'backIn' })
            .call(() => {
                this.node.active = false;
            })
            .start();
    }

    /** Reset to idle state */
    idle() {
        this.node.scale = 1;
        this.node.opacity = 255;
        this.node.active = true;
    }

    /** Animate symbol expanding to wild */
    expandToWild(wildCode: string, duration: number = 0.4, onComplete?: () => void) {
        cc.Tween.stopAllByTarget(this.node);
        cc.tween(this.node)
            .to(duration * 0.4, { scale: 1.3 }, { easing: 'backOut' })
            .call(() => {
                this.setCoreSymbol(wildCode);
            })
            .to(duration * 0.3, { scale: 0.9 }, { easing: 'sineIn' })
            .to(duration * 0.3, { scale: 1.0 }, { easing: 'bounceOut' })
            .call(() => {
                if (onComplete) onComplete();
            })
            .start();
    }
}